import{_ as t,C as o,o as l,c as n,a2 as s,E as i,j as e,a as p}from"./chunks/framework.e-meDy3u.js";const P=JSON.parse('{"title":"Q4 · 后台没 API、只能导出 Excel，怎么办？","description":"","frontmatter":{},"headers":[],"relativePath":"q4.md","filePath":"q4.md"}'),d={name:"q4.md"};function h(c,a,u,x,g,m){const r=o("EscalationLadder");return l(),n("div",null,[a[0]||(a[0]=s('<h1 id="q4-·-后台没-api、只能导出-excel-怎么办" tabindex="-1">Q4 · 后台没 API、只能导出 Excel，怎么办？ <a class="header-anchor" href="#q4-·-后台没-api、只能导出-excel-怎么办" aria-label="Permalink to &quot;Q4 · 后台没 API、只能导出 Excel，怎么办？&quot;">​</a></h1><p class="hqq-lede">约束条件不是障碍，是设计的起点。取数没有接口，入库侧完全可控——两侧分开处理。</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p><strong>没 API 照跑，这对第一版不是障碍。</strong></p><p>我要的不是实时数据流，是每天一次、口径固定、能对上账的回收数据进库。导出 Excel 就能满足，一行研发排期都不用等。</p><hr><h2 id="把两侧分清-取数在抖音侧-入库在飞书侧" tabindex="-1">把两侧分清：取数在抖音侧，入库在飞书侧 <a class="header-anchor" href="#把两侧分清-取数在抖音侧-入库在飞书侧" aria-label="Permalink to &quot;把两侧分清：取数在抖音侧，入库在飞书侧&quot;">​</a></h2><p><strong>取数（抖音侧）：</strong> 没有接口，现实入口就是人工导出 Excel。要自动化，路子不是等接口，是浏览器插件——跑在已登录的浏览器里，一键导出，不用资质、不用模拟登录。<strong>但第一版连插件都先不搭</strong>，就让人点一下导出。先把闭环跑通证明有用，再决定值不值得投自动化。</p><p><strong>入库（飞书侧）：</strong> 库建在飞书，飞书有全套 API 且立即可用，脚本把清洗好的数据批量写回表里，这一段稳、全自动。</p><hr><h2 id="七步-前三步是关键" tabindex="-1">七步，前三步是关键 <a class="header-anchor" href="#七步-前三步是关键" aria-label="Permalink to &quot;七步，前三步是关键&quot;">​</a></h2><p><strong>第一步：主键先定，用素材 ID，不用计划名。</strong></p><p>这是整件事的地基。千川报表里有创意/素材 ID，这是最稳的主键——一条素材可能挂在多个计划下，用计划名做键会漏掉素材维度的归并，而且批量托管的计划名未必让投手逐条自定义。主键落在素材 ID 上，计划名里的实验编号（格式定死，如 <code>HQ77-20260709-A1</code>）只作辅助校验。这一步在投放前约定好，命名对了后面全自动，命名乱了脚本也拼不回来。</p><p><strong>第二步：每天固定时间导出 Excel。</strong></p><p>谁导、几点导、导哪几张报表，写进 SOP。文件名按日期和平台命名，不靠人脑记。</p><p><strong>第三步：脚本清洗 Excel。</strong></p><p>统一列名、时间格式、字段口径。平台改一次导出格式，只改这一个清洗脚本，别处不动。</p><p><strong>第四步之后（全是脚本）：</strong></p><ul><li>用素材 ID 当主键，回写飞书表（走 API 批量写）</li><li>匹配失败进异常队列，绝不自动覆盖——宁可漏、不可脏</li><li>每次导入留原始文件 + 导入日志，随时能查</li></ul><p>整条链人只碰两个点：<strong>定命名（一次）、点导出（每天一下）</strong>。</p><hr><h2 id="取数自动化的路径-分级-按值不值得往上走" tabindex="-1">取数自动化的路径（分级，按值不值得往上走） <a class="header-anchor" href="#取数自动化的路径-分级-按值不值得往上走" aria-label="Permalink to &quot;取数自动化的路径（分级，按值不值得往上走）&quot;">​</a></h2>',22)),i(r),a[1]||(a[1]=e("p",null,"浏览器插件这条路经过实测验证——飞书文档可以一键导出为 markdown，千川后台导出 Excel 同理。不是纸上谈兵。",-1)),a[2]||(a[2]=e("hr",null,null,-1)),a[3]||(a[3]=e("h2",{id:"诚实边界",tabindex:"-1"},[p("诚实边界 "),e("a",{class:"header-anchor",href:"#诚实边界","aria-label":'Permalink to "诚实边界"'},"​")],-1)),a[4]||(a[4]=e("p",null,"没接口就没实时性。第一版是每天一次的节奏，不是实时大屏，这是硬约束。实时数据需要资质接口，第一版不做此承诺。",-1)),a[5]||(a[5]=e("p",null,"命名规范是这套的命门，靠人执行。解法是把它做进投放计划模板（能选就不手打）+ 每日入库前的命名合规校验（不合规当场退回投放的人改）+ 异常队列。用流程兜人性，不指望自觉。",-1))])}const f=t(d,[["render",h]]);export{P as __pageData,f as default};
